{"cmd":"set -e
# temp/临时目录命名扫描
printf '=== temp目录候选 ===\n';
for base in /tmp /private/tmp /var/tmp /private/var/tmp; do
  [ -d "$base" ] || continue
  echo "-- $base";
  find "$base" -mindepth 1 -maxdepth 1 -type d \( -name 'mac-*' -o -name 'mac_cleanup*' -o -name 'mac_48h*' -o -name 'codex*' -o -name 'eei*' -o -name 'adp*' -o -name 'playwright*' -o -name 'node-compile-cache' -o -name 'pytest-of-*' -o -name 'F3CNN*' -o -name 'moomoo*' -o -name 'codex-browser-use' \) -mtime +1 2>/dev/null | while read -r d; do du -sh "$d" 2>/dev/null; done | sed 's/^/  /' | head -n 200;
done

# private/var/folders T 下候选（按名称 + mtime）
printf '\n=== var/folders T候选 ===\n';
find /private/var/folders -type d -path '*/T/*' -maxdepth 5 2>/dev/null | while read -r tdir; do
  base=$(basename "$tdir")
  case "$base" in
    mac-*|mac_48h*|codex*|eei*|adp*|playwright*|F3CNN*|moomoo*|MSau* )
      if [ $(find "$tdir" -maxdepth 1 -type f -mtime +1 | wc -l) -gt 0 ] || [ $(find "$tdir" -maxdepth 1 -type d -mtime +1 | wc -l) -gt 0 ]; then
        du -sh "$tdir" 2>/dev/null | sed 's/^/  /'
      fi
      ;;
  esac
done | head -n 200

# 系统可疑更新/诊断/预览路径扫描（用户可访问）
printf '\n=== 系统用户区高可清理项扫描 ===\n';
for p in "$HOME/Library/Caches/com.apple.Spotlight" "$HOME/Library/Caches/com.apple.desktopservices" "$HOME/Library/Caches/com.apple.QuickLook" "$HOME/Library/Caches/com.apple.iconservices" "$HOME/Library/Logs/com.apple" "$HOME/Library/Logs/DiagnosticReports" "$HOME/Library/Preferences/ByHost" "$HOME/Library/Application Support/CrashReporter" "$HOME/Library/Caches/com.apple.Siri" "$HOME/Library/Application Support/com.apple.sharedfilelist"; do
  if [ -d "$p" ] || [ -f "$p" ]; then
    sz=$(du -sh "$p" 2>/dev/null | awk '{print $1}');
    echo "$sz\t$p";
  fi
done
","yield_time_ms":10000,"max_output_tokens":12000}

{"cmd":"echo '=== remaining candidate sizes ==='; du -sh "$HOME/Library/Caches/com.openai.codex" "$HOME/Library/Logs/com.openai.codex" "$HOME/Library/Caches/com.alibaba.DingTalkMac" "$HOME/Library/Application\ Support/Code/Cache" "$HOME/Library/Application\ Support/Codex/Default" "$HOME/Library/Application\ Support/DingTalkMac" "$HOME/Library/Containers/com.moomoo.mm-mac/Data/Library/Application\ Support/Common" "$HOME/Library/Containers/com.moomoo.mm.nx/Data/Library/Application\ Support/Common" "$HOME/.cache" "$HOME/Library/Caches/com.microsoft.VSCode" "$HOME/Library/Caches/com.microsoft.VSCode.ShipIt" 2>/dev/null | sed 's/^/  /'; echo '---'; 
for base in /tmp /private/tmp /var/tmp /private/var/tmp; do
  echo "-- $base matching stale names at >1d --";
  find "$base" -mindepth 1 -maxdepth 1 -type d -mtime +1 \( -name 'mac-*' -o -name 'mac_cleanup*' -o -name 'mac_48h*' -o -name 'codex*' -o -name 'eei*' -o -name 'adp*' -o -name 'playwright*' -o -name 'node-compile-cache' -o -name 'pytest-of-*' -o -name 'F3CNN*' -o -name 'moomoo*' -o -name 'codex-browser-use' \) -print; done","yield_time_ms":10000}

{"cmd":"for base in /tmp /private/tmp /var/tmp /private/var/tmp /private/var/folders/0w/kwy8k87s32qggj0hml1rhhn00000gn/T; do 
  echo "-- $base";
  find "$base" -maxdepth 3 -mindepth 1 -type d \( -name 'mac-*' -o -name 'mac_cleanup*' -o -name 'mac_48h*' -o -name 'codex*' -o -name 'eei*' -o -name 'adp*' -o -name 'playwright*' -o -name 'node-compile-cache' -o -name 'pytest-of-*' -o -name 'F3CNN*' -o -name 'moomoo*' -o -name 'codex-browser-use' \) -mtime +1 -print; done

echo '---'; du -sh /System/Volumes/Data | awk '{printf "total_k=%d free_k=%d\n", $2,$4}'; echo '---'; df -k /System/Volumes/Data | tail -n 1","yield_time_ms":10000}

