{"cmd":"DR="$HOME/Library/Logs/DiagnosticReports"
if [ -d "$DR" ]; then
  echo "DiagnosticReports exists"
  find "$DR" -maxdepth 1 -type f | wc -l | awk '{print "files",$1}';
  echo "Top oldest/ newest samples:";
  find "$DR" -type f -mtime +7 -print0 | xargs -0 -n1 -I{} sh -c 'stat -f "%m %N" "{}"' 2>/dev/null | sort -n | head -n 5 | awk '{print $0}'
fi","max_output_tokens":12000}

